from collections import deque

def parse(input: str) -> list[list[str]]:
    return [list(line) for line in input.split("\n")]

def solve(grid: list[list[str]]) -> int:
    queue = deque()
    for r in range(len(grid)):
        for c in range(len(grid[0])):
            if can_remove(grid, r, c):
                queue.append((r, c))
    
    while queue:
        r, c = queue.popleft()
        if can_remove(grid, r, c):
            grid[r][c] = 'x'
            for nr in range(r-1, r+2):
                for nc in range(c-1, c+2):
                    if can_remove(grid, nr, nc):
                        queue.append((nr, nc))
    return count_removed(grid)


def count_removed(grid: list[list[str]]) -> int:
    return sum([line.count('x') for line in grid])

def can_remove(grid: list[list[str]], r: int, c: int) -> bool:
    if r < 0 or r == len(grid) or c < 0 or c == len(grid[0]) or grid[r][c] != '@':
        return False

    neighbor_towels = 0
    for neighbor_r in range(r-1, r+2):
        for neighbor_c in range(c-1, c+2):
            if (
                neighbor_r >= 0 and neighbor_r < len(grid)
                and neighbor_c >= 0 and neighbor_c < len(grid[0])
                and not (neighbor_r == r and neighbor_c == c)
                and grid[neighbor_r][neighbor_c] == '@'
            ):
                neighbor_towels += 1
    return neighbor_towels < 4


### Main ###
print(solve(parse(INPUT)))